const items = $input.all();

const summary = {
  total_processados: items.length,
  workflows_executados: items.map(item => ({
    workflow: item.json.workflow_destino || 'unknown',
    tipo: item.json.tipo_email || 'unknown',
    status: 'processado'
  }))
};

console.log('=== RESUMO DO PROCESSAMENTO ===');
console.log(JSON.stringify(summary, null, 2));

return [{ json: summary }];

// ==========================
// CONTEXTO & NORMALIZAÇÃO
// ==========================
const item = $input.first();

// Normalizados (para regras)
const subject = (item.json.subject || '').toLowerCase();
const body = (item.json.bodyPreview || '').toLowerCase();
const from = (item.json.from?.emailAddress?.address || item.json.from || '').toLowerCase();
const fromName = (item.json.from?.emailAddress?.name || '').toLowerCase();

const attachments = item.binary ? Object.keys(item.binary) : [];
const attachmentNames = attachments
  .map(key => (item.binary[key].fileName || '').toLowerCase())
  .join(' ');

// Crus (para repasse aos filhos / auditoria)
const email = {
  id: item.json.id ?? null,
  conversationId: item.json.conversationId ?? null,
  internetMessageId: item.json.internetMessageId ?? null,
  subject: item.json.subject ?? null,
  bodyPreview: item.json.bodyPreview ?? null,
  body: {
    contentType: item.json.body?.contentType ?? null,
    content: item.json.body?.content ?? null,
  },
  from: {
    address: item.json.from?.emailAddress?.address ?? item.json.from?.address ?? (typeof item.json.from === 'string' ? item.json.from : null),
    name: item.json.from?.emailAddress?.name ?? null,
  },
  to: item.json.toRecipients ?? item.json.to ?? null,
  cc: item.json.ccRecipients ?? item.json.cc ?? null,
  receivedAt: item.json.receivedDateTime ?? item.json.dateTimeReceived ?? null,
  headers: item.json.headers ?? null,
  hasAttachments: (item.json.hasAttachments != null)
    ? item.json.hasAttachments
    : (Array.isArray(attachments) && attachments.length > 0),
  attachmentsMeta: attachments.map(k => ({
    key: k,
    fileName: item.binary?.[k]?.fileName ?? null,
    mimeType: item.binary?.[k]?.mimeType ?? null,
    fileSize: item.binary?.[k]?.fileSize ?? null,
  })),
};

const email_norm = {
  subject_lc: subject,
  body_preview_lc: body,
  from_lc: from,
  from_name_lc: fromName,
  attachment_names_lc: attachmentNames,
};

console.log('=== EMAIL RECEBIDO ===');
console.log('From:', from);
console.log('Subject:', subject);
console.log('Body Preview:', body.substring(0, 100));
console.log('Anexos:', attachmentNames || 'nenhum');

// ====================================
// PRIORIDADE MÁXIMA: REPORTS@IDTDNA.COM
// ====================================
// Estes e-mails SEMPRE devem ser processados, independente de outras regras

if (from.includes('reports@idtdna.com')) {
  console.log('🔥 REMETENTE PRIORITÁRIO: reports@idtdna.com');

  // PRIORIDADE 1A: STANDARD DAILY ORDER (do IDT)
  if (
    subject.includes('standard daily order') || 
    attachmentNames.includes('standard daily order') ||
    attachmentNames.includes('standard_daily_order')
  ) {
    console.log('✅ ROTA: STANDARD DAILY ORDER (IDT)');
    return [{
      json: {
        workflow_destino: 'standard_daily_order',
        workflow_id: 'IHp8cdMly0eUwIBJ',
        tipo_email: 'standard_daily_order',
        email,
        email_norm,
      },
      binary: item.binary,
    }];
  }

  // PRIORIDADE 1B: AUTOMATED DAILY SHIPMENT (do IDT)
  if (
    subject.includes('automated daily shipment') ||
    subject.includes('daily shipment') ||
    attachmentNames.includes('automated daily shipment') ||
    attachmentNames.includes('automated_daily_shipment') ||
    (subject.includes('shipment') && attachmentNames.includes('.xlsx'))
  ) {
    console.log('✅ ROTA: AUTOMATED DAILY SHIPMENT (IDT)');
    return [{
      json: {
        workflow_destino: 'automated_daily_shipment',
        workflow_id: 'mjjs155pSZ1dbKaE',
        tipo_email: 'automated_daily_shipment',
        email,
        email_norm,
      },
      binary: item.binary,
    }];
  }

  // Se for do IDT mas não identificado, marcar para revisão
  console.log('⚠️ E-mail do IDT não classificado - requer revisão');
  return [{
    json: {
      workflow_destino: 'email_nao_classificado',
      tipo_email: 'idt_nao_classificado',
      razao: 'email_from_idt_not_matching_rules',
      email,
      email_norm,
    },
    binary: item.binary,
  }];
}

// ====================================
// FILTROS DE SPAM E EMAILS IRRELEVANTES
// ====================================
// Agora que já processamos os e-mails prioritários do IDT,
// podemos aplicar os filtros de spam normalmente

const spamKeywords = [
  'unsubscribe', 'click here', 'congratulations', 'winner', 'prize',
  'free money', 'viagra', 'casino', 'lottery', 'urgent action required',
  'verify your account', 'suspended account', 'reset password',
  'singles in your area', 'weight loss', 'bitcoin', 'cryptocurrency'
];

const suspiciousDomains = [
  'noreply', 'no-reply', 'donotreply', 'mailer-daemon',
  'postmaster', 'newsletter', 'marketing'
];

const isSpamByKeywords = spamKeywords.some(keyword =>
  subject.includes(keyword) || body.includes(keyword)
);

const isSuspiciousDomain = suspiciousDomains.some(domain =>
  from.includes(domain)
);

const isAutoReply = subject.includes('auto') && (
  subject.includes('reply') ||
  subject.includes('response') ||
  subject.includes('out of office')
);

// MELHORADO: System notification agora é mais restritivo
// Só é system notification se tiver notification/alert MAS NÃO tiver:
// - Indicadores de tracking (PO, MAWB, HAWB, processo, carga)
// - Indicadores de shipment/envio
// - Números relevantes
const hasTrackingOrShipmentIndicators = 
  subject.includes('po ') || 
  subject.includes('mawb') || 
  subject.includes('hawb') ||
  subject.includes('processo') ||
  subject.includes('carga') ||
  subject.includes('shipment') ||
  subject.includes('envio') ||
  subject.includes('tracking') ||
  /\bpo\s*\d+/i.test(subject) ||
  /\d{3,}/.test(subject);

const isSystemNotification = (
  (subject.includes('notification') || subject.includes('alert')) &&
  !hasTrackingOrShipmentIndicators &&
  attachments.length === 0 // System notifications geralmente não têm anexos
);

if (isSpamByKeywords || isSuspiciousDomain || isAutoReply || isSystemNotification) {
  console.log('⚠️ ROTA: EMAIL IRRELEVANTE/SPAM');
  console.log('Razão:', 
    isSpamByKeywords ? 'spam_keywords' :
    isSuspiciousDomain ? 'suspicious_domain' :
    isAutoReply ? 'auto_reply' :
    'system_notification'
  );
  return [{
    json: {
      workflow_destino: 'email_irrelevante',
      tipo_email: 'spam_ou_irrelevante',
      razao: isSpamByKeywords ? 'spam_keywords' :
            isSuspiciousDomain ? 'suspicious_domain' :
            isAutoReply ? 'auto_reply' :
            'system_notification',
      email,
      email_norm,
    },
    binary: item.binary,
  }];
}

// ====================================
// HELPERS PARA BIO-RAD
// ====================================

function isBioRadEmail() {
  const fromBioRad = from.includes('biorad') || 
                     from.includes('bio-rad') ||
                     fromName.includes('biorad') || 
                     fromName.includes('bio-rad');

  const subjectBioRad = subject.includes('biorad') ||
                        subject.includes('bio-rad') ||
                        subject.includes('síntese biotecnologia') ||
                        subject.includes('sintese biotecnologia');

  const bodyBioRad = body.includes('biorad') ||
                     body.includes('bio-rad') ||
                     body.includes('síntese biotecnologia') ||
                     body.includes('sintese biotecnologia');

  const attachmentBioRad = /pedido\s+n[uú]mero\s+\d+\.pdf/i.test(attachmentNames) ||
                           attachmentNames.includes('ordervision.pdf');

  return fromBioRad || subjectBioRad || bodyBioRad || attachmentBioRad;
}

function hasPedidoIndicators() {
  const hasOC = /\boc\s*\d+/i.test(subject) || 
                /\boc\s*\d+/i.test(attachmentNames) ||
                subject.includes('ordem de compra');

  const hasPedidoWord = subject.includes('pedido') || 
                        subject.includes('novo pedido') ||
                        body.includes('segue anexo novo pedido') ||
                        body.includes('pedido da bio-rad');

  const hasPedidoPDF = /oc[\s_-]*\d+.*\.pdf/i.test(attachmentNames) ||
                       attachmentNames.includes('ordervision.pdf');

  return hasOC || hasPedidoWord || hasPedidoPDF;
}

function hasConfirmacaoIndicators() {
  const explicitConfirm = subject.includes('confirmação') || 
                          subject.includes('confirmacao') ||
                          subject.includes('confirmaçao') ||
                          body.includes('confirmação') ||
                          body.includes('confirmacao') ||
                          body.includes('segue anexo confirmação') ||
                          body.includes('segue anexo confirmacao');

  const pedidoNumeroPattern = /pedido\s+n[uú]mero\s+\d+/i.test(subject) ||
                               /pedido\s+n[uú]mero\s+\d+\.pdf/i.test(attachmentNames);

  return explicitConfirm || pedidoNumeroPattern;
}

// ====================================
// CLASSIFICAÇÃO DE EMAILS VÁLIDOS
// (Ordem de prioridade após IDT)
// ====================================

// PRIORIDADE 2: STANDARD DAILY ORDER (outros remetentes)
if (subject.includes('standard daily order') || subject.includes('daily order') || attachmentNames.includes('standard daily order')) {
  console.log('✅ ROTA: STANDARD DAILY ORDER');
  return [{
    json: {
      workflow_destino: 'standard_daily_order',
      workflow_id: 'IHp8cdMly0eUwIBJ',
      tipo_email: 'standard_daily_order',
      email,
      email_norm,
    },
    binary: item.binary,
  }];
}

// PRIORIDADE 3: AUTOMATED DAILY SHIPMENT (outros remetentes)
if (
  subject.includes('automated daily shipment') ||
  subject.includes('daily shipment') ||
  attachmentNames.includes('automated daily shipment') ||
  attachmentNames.includes('shipment')
) {
  console.log('✅ ROTA: AUTOMATED DAILY SHIPMENT');
  return [{
    json: {
      workflow_destino: 'automated_daily_shipment',
      workflow_id: 'mjjs155pSZ1dbKaE',
      tipo_email: 'automated_daily_shipment',
      email,
      email_norm,
    },
    binary: item.binary,
  }];
}

// PRIORIDADE 4: BIO-RAD CONFIRMAÇÃO (verificar ANTES do pedido)
if (isBioRadEmail() && hasConfirmacaoIndicators()) {
  console.log('✅ ROTA: BIO-RAD CONFIRMAÇÃO');
  return [{
    json: {
      workflow_destino: 'biorad_confirmacao',
      workflow_id: 'jEEaInq4vrueL4S5',
      tipo_email: 'biorad_confirmacao',
      email,
      email_norm,
    },
    binary: item.binary,
  }];
}

// PRIORIDADE 5: BIO-RAD PEDIDO (OC)
if (isBioRadEmail() && hasPedidoIndicators()) {
  console.log('✅ ROTA: BIO-RAD PEDIDO');
  return [{
    json: {
      workflow_destino: 'biorad_pedido',
      workflow_id: 'n6Cb54wYrMkyBTWa',
      tipo_email: 'biorad_pedido',
      email,
      email_norm,
    },
    binary: item.binary,
  }];
}

// PRIORIDADE 5B: TRACKING PÓS-ARMAZÉM (warehouse receipt / WRN)
if (
  subject.includes('warehouse receipt') || subject.includes('wrn') || subject.includes('receipt number') ||
  body.includes('warehouse receipt') || body.includes('wrn') || body.includes('receipt number')
) {
  console.log('✅ ROTA: TRACKING PÓS-ARMAZÉM (Warehouse Receipt/WRN)');
  return [{
    json: {
      workflow_destino: 'tracking_pos_armazem',
      workflow_id: 'jYJlVMhTKVxoNkT1',
      tipo_email: 'tracking_warehouse_receipt',
      email,
      email_norm,
    },
    binary: item.binary,
  }];
}

// PRIORIDADE 6: AUTORIZAÇÃO DE CONSOLIDAÇÃO (PO + palavras-chave)
if (
  subject.includes('po ') &&
  (body.includes('ciente') || body.includes('considere') ||
   body.includes('autoriza') || body.includes('ok'))
) {
  console.log('✅ ROTA: TRACKING PÓS-ARMAZÉM (Autorização)');
  return [{
    json: {
      workflow_destino: 'tracking_pos_armazem',
      workflow_id: 'jYJlVMhTKVxoNkT1',
      tipo_email: 'autorizacao_consolidacao',
      email,
      email_norm,
    },
    binary: item.binary,
  }];
}

// PRIORIDADE 7: PLANILHA DE LOTES (subject ou anexo contém 'lote')
if (
  ((subject.includes('lote') || subject.includes('planilha')) &&
   (attachmentNames.includes('.xlsx') || attachmentNames.includes('.xls'))) ||
  (attachmentNames.includes('lote') &&
   (attachmentNames.includes('.xlsx') || attachmentNames.includes('.xls')))
) {
  console.log('✅ ROTA: PLANILHA DE LOTES');
  return [{
    json: {
      workflow_destino: 'planilha_lotes',
      workflow_id: 'G9ToKNnnyM4SPv3Q',
      tipo_email: 'planilha_lotes',
      email,
      email_norm,
    },
    binary: item.binary,
  }];
}

// PRIORIDADE 8: TRACKING COM PO NO SUBJECT (QUALQUER EMAIL COM "PO XXX")
if (/\bpo\s*\d+/i.test(subject)) {
  console.log('✅ ROTA: TRACKING PÓS-ARMAZÉM (PO detectado no subject)');
  return [{
    json: {
      workflow_destino: 'tracking_pos_armazem',
      workflow_id: 'jYJlVMhTKVxoNkT1',
      tipo_email: 'tracking_po',
      email,
      email_norm,
    },
    binary: item.binary,
  }];
}

// PRIORIDADE 9: TRACKING COM PALAVRA-CHAVE EXPLÍCITA (carga/processo/mawb/hawb)
// NOTA: Removido o match genérico /\d{3,}/ que causava falsos positivos
if (!isBioRadEmail() && (subject.includes('carga') || subject.includes('processo') || subject.includes('mawb') || subject.includes('hawb'))) {
  console.log('✅ ROTA: TRACKING PÓS-ARMAZÉM (Carga/Processo)');
  return [{
    json: {
      workflow_destino: 'tracking_pos_armazem',
      workflow_id: 'jYJlVMhTKVxoNkT1',
      tipo_email: 'tracking_carga',
      email,
      email_norm,
    },
    binary: item.binary,
  }];
}

// ====================================
// ANÁLISE FINAL
// ====================================

const hasBusinessIndicators = (
  from.includes('.com') || from.includes('.br') || from.includes('.net')
) && (
  subject.length > 5 &&
  !subject.includes('test') &&
  !subject.includes('teste')
);

if (hasBusinessIndicators) {
  console.log('⚠️ ROTA: EMAIL NÃO CLASSIFICADO (requer revisão)');
  return [{
    json: {
      workflow_destino: 'email_nao_classificado',
      tipo_email: 'requer_revisao_manual',
      razao: 'business_email_not_matching_rules',
      email,
      email_norm,
    },
    binary: item.binary,
  }];
}

console.log('⚠️ ROTA: EMAIL IRRELEVANTE (descarte)');
return [{
  json: {
    workflow_destino: 'email_irrelevante',
    tipo_email: 'sem_classificacao',
    razao: 'no_business_indicators',
    email,
    email_norm,
  },
  binary: item.binary,
}];
